package main

import (
	"fmt"
	"math/rand"
	"time"
)

func main() {
	// Seed the random number generator.
	// Important: Use a unique seed, like current time,
	// otherwise, you'll get the same sequence every run.
	// In Go 1.20+, rand.Seed is deprecated for top-level functions.
	// Instead, create a new source: r := rand.New(rand.NewSource(time.Now().UnixNano()))
	// And then call r.Intn() etc.
	// This example uses the older global rand for simplicity.
	rand.Seed(time.Now().UnixNano())

	// Generate a random integer between 0 (inclusive) and 100 (exclusive)
	randomInt := rand.Intn(100)
	fmt.Println("Random Integer [0-99]:", randomInt)

	// Generate a random float between 0.0 (inclusive) and 1.0 (exclusive)
	randomFloat := rand.Float64()
	fmt.Println("Random Float [0.0, 1.0):", randomFloat)

	// Generate an integer in a specific range [min, max]
	min := 10
	max := 20
	randomInRange := rand.Intn(max-min+1) + min
	fmt.Printf("Random Integer in range [%d, %d]: %d\n", min, max, randomInRange)

	// Select a random element from a slice
	fruits := []string{"apple", "banana", "cherry"}
	if len(fruits) > 0 {
		randomFruit := fruits[rand.Intn(len(fruits))]
		fmt.Println("Random fruit:", randomFruit)
	}
}

