package main

import "fmt"

// reverseString correctly reverses a string with multi-byte characters (like emojis or other languages).
func reverseString(s string) string {
	// Convert string to a slice of runes to handle multi-byte characters correctly.
	runes := []rune(s)
	// Get the number of runes in the slice.
	n := len(runes)
	// Swap characters from the beginning and end, moving towards the center.
	for i := 0; i < n/2; i++ {
		runes[i], runes[n-1-i] = runes[n-1-i], runes[i]
	}
	// Convert the slice of runes back to a string.
	return string(runes)
}

func main() {
	original := "Hello, 世界"
	reversed := reverseString(original)
	fmt.Printf("Original: %s\n", original)
	fmt.Printf("Reversed: %s\n", reversed)
}

