package main

import (
	"fmt"
	"math/big" // Import big package for arbitrary-precision arithmetic
)

// fibonacci calculates the nth Fibonacci number iteratively using big.Int.
func fibonacci(n int) *big.Int {
	if n < 0 {
		// Or handle error as you see fit
		return big.NewInt(-1)
	}
	if n <= 1 {
		return big.NewInt(int64(n))
	}

	a := big.NewInt(0)
	b := big.NewInt(1)

	for i := 2; i <= n; i++ {
		// The next Fibonacci number is the sum of the previous two.
		// a, b = b, a+b
		a.Add(a, b) // a becomes a+b
		a, b = b, a   // Swap a and b
	}
	return b
}

func main() {
	n := 10
	fmt.Printf("The %dth Fibonacci number is: %s\n", n, fibonacci(n))

	// Example with a large number that would overflow standard integers
	largeN := 90
	fmt.Printf("The %dth Fibonacci number is: %s\n", largeN, fibonacci(largeN))
}

