package main

import (
	"fmt"
	"math/big" // Use big.Int for arbitrary precision
)

// factorial calculates n! using big.Int for large numbers.
func factorial(n int) *big.Int {
	if n < 0 {
		// Factorial is not defined for negative numbers
		return big.NewInt(-1)
	}
	result := big.NewInt(1)
	if n == 0 {
		return result // Factorial of 0 is 1
	}

	// Multiply result by each integer from 1 to n
	for i := 1; i <= n; i++ {
		result.Mul(result, big.NewInt(int64(i)))
	}
	return result
}

func main() {
	num := 5
	fmt.Printf("Factorial of %d is %d\n", num, factorial(num))

	// Example with a number that would overflow int64
	largeNum := 30
	fmt.Printf("Factorial of %d is %s\n", largeNum, factorial(largeNum))
}

