package main

import (
	"fmt"
	"math/big" // Use big.Int for checking large primes
)

// isPrime checks if a number is prime using big.Int's ProbablyPrime method.
// This is a probabilistic test, sufficient for most applications.
// For deterministic checks on smaller numbers, an iterative approach is fine.
func isPrime(n int64) bool {
	if n <= 1 {
		return false
	}
	nBig := big.NewInt(n)
	// ProbablyPrime(0) is 100% accurate for n < 2^64.
	// For cryptographic purposes, use a higher certainty level (e.g., 20).
	return nBig.ProbablyPrime(0)
}

func main() {
	numbersToCheck := []int64{2, 3, 4, 17, 25, 29, 97, 100, 1, -5, 1000000007}

	for _, num := range numbersToCheck {
		if isPrime(num) {
			fmt.Printf("%d is a prime number.\n", num)
		} else {
			fmt.Printf("%d is not a prime number.\n", num)
		}
	}
}

