package main

import (
	"fmt"
	"os" // Use os package for file operations
)

func main() {
	filePath := "example_go.txt"

	// Create a dummy file for the example to work
	// Permissions 0644 are standard for files (read/write for owner, read for others).
	err := os.WriteFile(filePath, []byte("Hello from Go file!\nSecond line."), 0644)
	if err != nil {
		fmt.Println("Error creating dummy file:", err)
		return
	}
	// 'defer' ensures the file is removed at the end of the function's execution.
	defer os.Remove(filePath)

	// Use os.ReadFile (the modern, simple way since Go 1.16)
	content, err := os.ReadFile(filePath)
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}

	fmt.Println("File Content:")
	fmt.Println(string(content)) // Convert byte slice to string to print
}

