package main

import (
	"fmt"
	"os"
)

func main() {
	filePath := "output_go.txt"
	content := "This content will be written to the file.\nHello Go!"

	// Use os.WriteFile (the modern, simple way since Go 1.16).
	// This creates the file if it doesn't exist, and overwrites it if it does.
	// Permissions 0644: owner can read/write, group/others can read.
	err := os.WriteFile(filePath, []byte(content), 0644)
	if err != nil {
		fmt.Println("Error writing to file:", err)
		return
	}

	fmt.Printf("Successfully wrote content to %s\n", filePath)

	// To append to a file, use os.OpenFile with specific flags.
	f, err := os.OpenFile(filePath, os.O_APPEND|os.O_WRONLY|os.O_CREATE, 0644)
	if err != nil {
		fmt.Println("Error opening file for append:", err)
		return
	}
	defer f.Close()

	if _, err = f.WriteString("\nThis line was appended."); err != nil {
		fmt.Println("Error appending to file:", err)
	}

	fmt.Println("Successfully appended content.")
}

