package main

import (
	"fmt"
	"os"
)

// fileExists checks if a file or directory at the given path exists.
func fileExists(filePath string) (bool, error) {
	_, err := os.Stat(filePath)
	if err == nil {
		return true, nil // Path exists
	}
	if os.IsNotExist(err) {
		return false, nil // Path does not exist
	}
	// Some other error occurred (e.g., permission denied)
	return false, err
}

func main() {
	// Create a dummy file and directory to check
	_ = os.WriteFile("temp_file.txt", []byte("check"), 0644)
	_ = os.Mkdir("temp_dir", 0755)
	// Defer cleanup to ensure dummies are removed
	defer os.Remove("temp_file.txt")
	defer os.Remove("temp_dir")

	pathsToCheck := []string{"temp_file.txt", "temp_dir", "non_existent_file.txt"}

	for _, path := range pathsToCheck {
		exists, err := fileExists(path)
		if err != nil {
			fmt.Printf("Error checking '%s': %v\n", path, err)
		} else {
			fmt.Printf("Does '%s' exist? %t\n", path, exists)
		}
	}
}

