package main

import (
	"fmt"
	"time"
)

func main() {
	// Get the current time in the local timezone.
	currentTime := time.Now()
	fmt.Println("Current Local Time:", currentTime)

	// Get the current time in UTC.
	utcTime := time.Now().UTC()
	fmt.Println("Current UTC Time:  ", utcTime)

	// Format the time. Go uses a specific reference date to define formats:
	// Mon Jan 2 15:04:05 MST 2006 (01/02 03:04:05PM '06 -0700)
	fmt.Println("Formatted (MM-DD-YYYY):", currentTime.Format("01-02-2006"))
	fmt.Println("Formatted (Time only): ", currentTime.Format("15:04:05"))
	fmt.Println("Formatted (with TZ): ", currentTime.Format(time.RFC1123Z))

	// Get individual components of the time.
	year, month, day := currentTime.Date()
	hour, min, sec := currentTime.Clock()
	weekday := currentTime.Weekday()
	fmt.Printf("Date: %d-%s-%d, Weekday: %s\n", year, month, day, weekday)
	fmt.Printf("Time: %02d:%02d:%02d\n", hour, min, sec)

	// Get Unix timestamp (seconds or nanoseconds since Jan 1, 1970 UTC).
	unixTimestamp := currentTime.Unix()
	unixNano := currentTime.UnixNano()
	fmt.Println("Unix Timestamp (seconds):", unixTimestamp)
	fmt.Println("Unix Timestamp (nanos):", unixNano)

	// Create a time from components.
	specificTime := time.Date(2025, time.July, 17, 9, 20, 39, 0, time.Local)
	fmt.Println("Specific Time Created:", specificTime)
}

