package main

import (
	"fmt"
)

// findMax finds the maximum value in a slice of integers.
// It returns an error if the slice is empty.
func findMax(numbers []int) (int, error) {
	if len(numbers) == 0 {
		return 0, fmt.Errorf("cannot find max in an empty slice")
	}

	maxVal := numbers[0] // Initialize max with the first element
	// Iterate through the rest of the slice
	for _, num := range numbers[1:] {
		if num > maxVal {
			maxVal = num // Update max if a larger number is found
		}
	}
	return maxVal, nil
}

func main() {
	data := []int{5, 2, 9, 1, 5, 6}
	maxVal, err := findMax(data)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("The maximum value in %v is %d\n", data, maxVal)
	}

	// Example with an empty slice
	emptyData := []int{}
	_, err = findMax(emptyData)
	if err != nil {
		fmt.Println("Error for empty slice:", err)
	}
}
